package com.hospital.management.service.impl;import com.hospital.management.dao.*;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.validation.MedicalRecordValidator;import org.junit.jupiter.api.*;import org.junit.jupiter.api.extension.ExtendWith;import org.mockito.*;import org.mockito.junit.jupiter.MockitoExtension;import java.util.*;import static org.junit.jupiter.api.Assertions.*;import static org.mockito.Mockito.*;
@ExtendWith(MockitoExtension.class)class MedicalRecordServiceImplTest {@Mock MedicalRecordDao records;@Mock AppointmentDao appointments;@Mock DoctorDao doctors;@Mock PatientDao patients;@Mock AuditLogDao audit;MedicalRecordServiceImpl service;@BeforeEach void setUp(){service=new MedicalRecordServiceImpl(records,appointments,doctors,patients,new MedicalRecordValidator(),audit);}@Test void patientCannotCreate()throws Exception{Appointment a=appointment("CONFIRMED",4L);when(appointments.findById(1L)).thenReturn(Optional.of(a));ServiceResult<Long>x=service.createRecord(form(),null,user("PATIENT",7L));assertEquals(ServiceResult.Status.FORBIDDEN,x.getStatus());verify(records,never()).create(any(),any());}@Test void missingAppointment()throws Exception{when(appointments.findById(1L)).thenReturn(Optional.empty());assertEquals(ServiceResult.Status.NOT_FOUND,service.createRecord(form(),null,user("ADMIN",1L)).getStatus());}@Test void scheduledCancelledAndNoShowAreBlocked()throws Exception{for(String status:List.of("SCHEDULED","CANCELLED","NO_SHOW")){when(appointments.findById(1L)).thenReturn(Optional.of(appointment(status,4L)));assertEquals(ServiceResult.Status.CONFLICT,service.createRecord(form(),null,user("ADMIN",1L)).getStatus());}}@Test void duplicateAppointmentIsRejected()throws Exception{when(appointments.findById(1L)).thenReturn(Optional.of(appointment("CONFIRMED",4L)));when(records.existsByAppointmentId(1L)).thenReturn(true);assertEquals(ServiceResult.Status.DUPLICATE,service.createRecord(form(),null,user("ADMIN",1L)).getStatus());}@Test void patientCanReadOwnButNotAnotherRecord()throws Exception{Patient p=new Patient();p.setPatientId(8L);p.setUserId(7L);p.setStatus("ACTIVE");when(patients.findAll(any(),eq("ACTIVE"))).thenReturn(new Page<>(List.of(p),1,100,1));MedicalRecord own=new MedicalRecord();own.setMedicalRecordId(1L);own.setPatientId(8L);MedicalRecord other=new MedicalRecord();other.setMedicalRecordId(2L);other.setPatientId(9L);when(records.findById(1L)).thenReturn(Optional.of(own));when(records.findById(2L)).thenReturn(Optional.of(other));AuthenticatedUser u=user("PATIENT",7L);assertTrue(service.getRecord(1L,u).isPresent());assertTrue(service.getRecord(2L,u).isEmpty());}private MedicalRecordForm form(){MedicalRecordForm f=new MedicalRecordForm();f.setAppointmentId(1L);f.setSymptoms("Valid symptoms");f.setDiagnosis("Valid diagnosis");return f;}private Appointment appointment(String s,Long d){Appointment a=new Appointment();a.setAppointmentId(1L);a.setPatientId(8L);a.setDoctorId(d);a.setStatus(s);return a;}private AuthenticatedUser user(String role,Long id){return new AuthenticatedUser(id,"user","u@example.com",role);}}
